INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('fire-eq-eng-moex-01173', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關液化石油氣容器認可作業規定之敘述，何者有誤？', '["內政部或內政部指定之專業機構受理個別認可之申請後，應按月排定個別認可計畫，並於受檢日三十 天前通知申請人", "型式認可之有效期限為三年，期限屆滿前三個月內得申請延期，每次延期期間為三年", "經型式認可者，應自取得型式認可書之日起二年內申請個別認可，經個別認可合格並取得液化石油氣 容器瓶身證明者，始得申購合格標示", "型式認可之審查結果，自受理之日起三個月內由本（內政）部以書面通知申請人"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01174', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「複合用途建築物判斷基準」規定之敘述，何者有誤？', '["供設置標準第十二條第一款至第四款各目用途使用之樓地板面積合計小於五十平方公尺，且較供住宅 使用之樓地板合計面積小時，該建築物視為住宅", "供設置標準第十二條第一款至第四款各目用途使用之樓地板面積合計，與供住宅使用之樓地板合計面 積大致相等時，應視為複合用途建築物", "供設置標準第十二條第一款至第四款各目用途使用之樓地板面積合計小於供住宅使用之樓地板面積合 計，且前者樓地板面積合計在一百五十平方公尺以上時，該建築物視為複合用途建築物", "供設置標準第十二條第一款至第四款各目用途使用之樓地板合計面積大於供住宅使用之樓地板合計面 積時，視為設置標準第十二條第一款至第四款各目用途之建築物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01175', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列消防法相關規定之敘述，何者有誤？', '["供公眾使用建築物之消防安全設備圖說，應由直轄市、縣（市）消防機關於主管建築機關許可完工前， 審查完成", "依各類場所消防安全設備設置標準設置之消防安全設備，其設計、監造應由消防設備師為之；其裝置、 檢修應由消防設備師或消防設備士為之", "前項", "消防安全設備之設計、監造、裝置及檢修，於消防設備師或消防設備士未達定量人數前，得由 現有相關專門職業及技術人員或技術士暫行為之；其期限由中央主管機關定之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01176', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「建築法」規定之敘述，何者有誤？', '["建築物應依核定之使用類組使用，其有變更使用類組或有第九條建造行為以外主要構造、防火區劃、 防火避難設施、消防設備、停車空間及其他與原核定使用不合之變更者，應申請變更雜項執照", "建築執照分為四種：建造執照、雜項執照、使用執照、拆除執照", "發現「危害公共安全者」，應以書面通知承造人或起造人或監造人，勒令停工或修改；必要時，得強 制拆除", "非供公眾使用建築物變更為供公眾使用，或原供公眾使用建築物變更為他種公眾使用時，直轄市、縣 （市）（局）主管建築機關應檢查其構造、設備及室內裝修。其有關消防安全設備部分應會同消防主 管機關檢查"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01177', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據一齊開放閥控制部之構造可以分為四種，包括：加壓型、減壓型、電磁型及下列何者？', '["光電型", "離子型", "電動型", "複合型"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01178', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「建築物之各樓層供避難及消防搶救用之有效開口」規定之敘述，何者有誤？', '["開口下端距樓地板面一百二十公分以內", "開口面臨道路或寬度三公尺以上之通路", "開口無柵欄且內部未設妨礙避難之構造或阻礙物", "開口為可自外面開啟或輕易破壞得以進入室內之構造。採一般玻璃門窗時，厚度應在六公厘以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01179', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '泡沫噴頭認可基準之耐洩漏試驗規定：將撒水頭施予多少kgf∕cm2之靜水壓力，保持5分鐘不得有漏 水現象？', '["25kgf∕cm2", "30kgf∕cm2", "35kgf∕cm2", "40kgf∕cm2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01180', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「防火區劃」規定之敘述，何者有誤？', '["防火構造建築物內之挑空部分、電扶梯間、安全梯之樓梯間、昇降機道、垂直貫穿樓板之管道間及其 他類似部分，應以具有半小時以上防火時效之牆壁、防火門窗等防火設備與該處防火構造之樓地板形 成區劃分隔", "昇降機道裝設之防火設備應具有遮煙性能。管道間之維修門並應具有一小時以上防火時效及遮煙性能", "前項昇降機道前設有昇降機間且併同區劃者，昇降機間出入口裝設具有遮煙性能之防火設備時，昇降 機道出入口得免受應裝設具遮煙性能防火設備之限制", "昇降機間出入口裝設之門非防火設備但開啟後能自動關閉且具有遮煙性能時，昇降機道出入口之防火 設備得免受應具遮煙性能之限制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01181', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依建築技術規則建築設計施工編，下列有關規定之敘述，何者有誤？', '["各種電氣、給排水、消防、空調等設備開關控制箱設置於防火區劃牆壁時，應以不破壞牆壁防火時效 性能之方式施作", "前項設備開關控制箱嵌裝於防火區劃牆壁者，該牆壁仍應具有一小時以上防火時效", "貫穿防火區劃牆壁或樓地板之電力管線、通訊管線及給排水管線或管線匣，與貫穿部位合成之構造， 應具有一小時以上之防火時效", "貫穿防火區劃牆壁或樓地板之風管，應在貫穿部位兩側之風管內裝設防火閘門或閘板，其與貫穿部位 合成之構造，並應具有一小時以上之防火時效"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01182', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關「排煙設備用閘門認可基準」規定之敘述，何者有誤？', '["防火閘門所設熱感應裝置之額定溫度不得小於閘門之額定溫度", "防火閘門動作餘隙之貫穿開口，在垂直面（如葉片與閘門框架間）不得超過9.5mm（3/8in），在水平 面（如聯鎖簾之葉片與葉片鉸節處）不得超過0.8mm（1/32in）", "防火閘門與其套管間之貫穿開口尺寸不得使直徑3.5mm（1/8in）之測桿貫穿開口全深", "多重閘門組件中兩框架接觸角落之貫穿開口尺寸不得使直徑6.4mm（1/4in）之測桿貫穿開口全深"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "48ec6d60df0f", "answer_pdf_sha1": "86cbc5773a37", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "301", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
